external_knowledge:
- 'authorization objects' can metaphorically represent gardeners;
- 'authorization fields' can be likened to flower beds in a nursery;
- 'flower beds' in this context symbolize the various areas or tasks managed by a gardener (or the different fields associated with each authorization object).

sql:
SELECT activity_name 
FROM activities 
WHERE activity_id > 10;

SELECT COUNT(auth_object_id) 
FROM authorization_objects
WHERE is_active = 1;

SELECT activity_id
FROM activity_audit
WHERE description = 'Activity modified';

SELECT COUNT(DISTINCT af.auth_object_id) AS num_auth_objects_with_dependencies
FROM authorization_field_dependencies afd
JOIN authorization_fields af ON af.field_id = afd.dependent_field_id;

SELECT COUNT(activity_id) 
FROM role_authorizations 
WHERE role_id = 1;

external_knowledge:
- 'roles that are in the shadow' refers to roles that are not default (is_default = 0);
- 'untouched by default status' means these roles are not marked as default;
- 'hold the hands of more than one seeker' means there are more than one user associated with the role;
- 'wandering in the labyrinth of permissionless activities' means these roles do not have any allowed activities (is_allowed = 0) and no authorization objects linked to them (auth_object_id IS NULL, activity_id IS NULL).

sql:
SELECT ao.auth_object_id
FROM authorization_objects ao
WHERE ao.is_active = 1 OR ao.category = 'Development';

SELECT ao.auth_object_id, ao.auth_object_name
FROM authorization_objects ao
JOIN authorization_object_hierarchy aoh ON ao.auth_object_id = aoh.child_auth_object_id;
